mapper.select:
select *
from batch.workflow_definition

where tenant_id = #{tenantId}

    and workflow_code like concat('%', #{workflowCode}, '%')


    and workflow_name like concat('%', #{workflowName}, '%')


    and workflow_type = #{workflowType}


    and version = #{version}


    and enabled = #{enabled}

order by workflow_code, version desc, id desc

    limit #{pageRequest.pageSize} offset (#{pageRequest.pageNo} - 1) * #{pageRequest.pageSize}

select count(1)
from batch.workflow_definition

where tenant_id = #{tenantId}

    and workflow_code like concat('%', #{workflowCode}, '%')


    and workflow_name like concat('%', #{workflowName}, '%')


    and workflow_type = #{workflowType}


    and version = #{version}


    and enabled = #{enabled}

select *
from batch.workflow_definition
where tenant_id = #{tenantId}
  and workflow_code = #{workflowCode}
  and version = #{version}
limit 1

select *
from batch.workflow_definition
where tenant_id = #{tenantId}
  and id = #{id}
limit 1

mapper.delete:
delete from batch.workflow_definition
where tenant_id = #{tenantId}
  and id = #{id}

mapper.update:
update batch.workflow_definition
set enabled = #{enabled},
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{id}

update batch.workflow_definition
set workflow_name = #{workflowName},
    workflow_type = #{workflowType},
    enabled = #{enabled},
    version = version + 1,
    updated_at = current_timestamp
where tenant_id = #{tenantId}
  and id = #{id}

      and version = #{expectedVersion}
